def backfill_credentials_from_user(apps, schema_editor):
    """Carry each student's login credentials over from their User onto the student
    account (role-native auth): same username + password hash, so when role-native login
    goes live they sign in unchanged. Runs per tenant schema."""
    Profile = apps.get_model("students", "StudentProfile")
